from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(64), unique=True, nullable=False)
    role = db.Column(db.String(64), default='user', nullable=False)
    account_status = db.Column(db.String(64), default='active', nullable=False)
    subscription_tier = db.Column(db.String(64), default='free', nullable=False)

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    current_user = User.query.get(current_user.id)  # assuming current_user is an admin
    user_to_update = User.query.get(user_id)
    
    if not user_to_update:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.json
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    
    for field in data:
        if field in allowed_fields:
            setattr(user_to_update, field, data[field])
    
    user_to_update.role = validate_role(user_to_update.role)
    user_to_update.account_status = validate_account_status(user_to_update.account_status)
    user_to_update.subscription_tier = validate_subscription_tier(user_to_update.subscription_tier)
    
    db.session.commit()
    return jsonify({'message': 'User updated successfully'}), 200

def validate_role(role):
    if role not in ['user', 'moderator', 'admin']:
        raise ValueError('Invalid role')
    return role

def validate_account_status(status):
    if status not in ['active', 'suspended']:
        raise ValueError('Invalid account status')
    return status

def validate_subscription_tier(tier):
    if tier not in ['free', 'pro', 'enterprise']:
        raise ValueError('Invalid subscription tier')
    return tier